13	/// Parse a brace-delimited block.
14	pub fn parse_block(ts: &mut TokenStream) -> Result<Block, CompileError> {
15	    ts.expect(TokenKind::LBrace)?;
16	    let mut stmts = Vec::new();
17	    while !ts.check(&TokenKind::RBrace) {
18	        stmts.push(parse_stmt(ts)?);
19	    }
20	    ts.expect(TokenKind::RBrace)?;
21	    Ok(Block { stmts })
22	}
23	
24	/// Parse either a brace-delimited block or a single statement.
25	/// Enables braceless control flow: `if (x) stmt;`
26	pub fn parse_body(ts: &mut TokenStream) -> Result<Block, CompileError> {
27	    if ts.check(&TokenKind::LBrace) {
28	        parse_block(ts)
29	    } else {
30	        let stmt = parse_stmt(ts)?;
31	        Ok(Block { stmts: vec![stmt] })
32	    }
33	}
34	
35	/// Parse a single statement.
36	pub fn parse_stmt(ts: &mut TokenStream) -> Result<Stmt, CompileError> {
37	    // Bare block: { ... } used as scope
38	    if ts.check(&TokenKind::LBrace) {
39	        let block = parse_block(ts)?;
40	        return Ok(Stmt::Block(block));
41	    }
42	    if ts.eat(TokenKind::Return) {
43	        return parse_return(ts);
44	    }
45	    if ts.eat(TokenKind::If) {
46	        return control::parse_if(ts);
47	    }
48	    if ts.eat(TokenKind::While) {
49	        return control::parse_while(ts);
50	    }
51	    if ts.eat(TokenKind::For) {
52	        return control::parse_for(ts);
53	    }
54	    if ts.eat(TokenKind::Do) {
55	        return control::parse_do_while(ts);
56	    }
57	    if ts.eat(TokenKind::Switch) {
58	        return control::parse_switch(ts);
59	    }
60	    if ts.eat(TokenKind::Break) {
61	        ts.expect(TokenKind::Semicolon)?;
62	        return Ok(Stmt::Break);
63	    }
64	    if ts.eat(TokenKind::Continue) {
65	        ts.expect(TokenKind::Semicolon)?;
66	        return Ok(Stmt::Continue);
67	    }
68	    if ts.eat(TokenKind::Asm) {
69	        return control::parse_asm(ts);
70	    }
71	    if ts.check(&TokenKind::Enum) && is_enum_definition(ts) {
72	        ts.advance(); // consume `enum`
73	        return tc24r_parser_enum::parse_enum_decl(ts);
74	    }
75	    if ts.eat(TokenKind::Typedef) {
76	        return tc24r_parser_typedef::parse_typedef_decl(ts);
77	    }
78	    if is_type_start(ts) {
79	        return parse_local_decl(ts);
80	    }
81	    let expr = parse_expr(ts)?;
82	    ts.expect(TokenKind::Semicolon)?;
83	    Ok(Stmt::Expr(expr))
