85	
86	/// Check if `enum` starts a definition (`enum {` or `enum tag {`)
87	/// as opposed to a variable declaration (`enum tag x;`).
88	fn is_enum_definition(ts: &TokenStream) -> bool {
89	    // Current token is Enum
90	    match ts.lookahead(1) {
91	        TokenKind::LBrace => true, // enum { ... }
92	        TokenKind::Ident(_) => {
93	            matches!(ts.lookahead(2), TokenKind::LBrace) // enum tag { ... }
94	        }
95	        _ => false,
96	    }
97	}
98	
99	fn parse_return(ts: &mut TokenStream) -> Result<Stmt, CompileError> {
100	    // void return: return;
101	    if ts.eat(TokenKind::Semicolon) {
102	        return Ok(Stmt::Return(Expr::IntLit(0)));
103	    }
104	    let expr = parse_expr(ts)?;
105	    ts.expect(TokenKind::Semicolon)?;
106	    Ok(Stmt::Return(expr))
107	}
108	
109	pub fn parse_local_decl(ts: &mut TokenStream) -> Result<Stmt, CompileError> {
110	    let base_ty = parse_type(ts)?;
111	    // Standalone struct definition: `struct tag { ... };`
112	    if ts.check(&TokenKind::Semicolon) {
113	        ts.advance();
114	        return Ok(Stmt::Expr(Expr::IntLit(0)));
115	    }
116	    let first = parse_one_declarator(ts, base_ty.clone())?;
117	    // Check for comma-separated additional declarators
118	    if !ts.check(&TokenKind::Comma) {
119	        ts.expect(TokenKind::Semicolon)?;
120	        return Ok(first);
121	    }
122	    let mut stmts = vec![first];
123	    while ts.eat(TokenKind::Comma) {
124	        stmts.push(parse_one_declarator(ts, base_ty.clone())?);
125	    }
126	    ts.expect(TokenKind::Semicolon)?;
127	    Ok(Stmt::Block(Block { stmts }))
128	}
129	
130	/// Parse a single variable declarator (name, optional array suffix,
131	/// optional initializer). Does NOT consume a trailing semicolon --
132	/// the caller (parse_local_decl) handles that after all declarators
133	/// are parsed. This separation is critical for multi-declarations
134	/// like `int x = 1, y = 2;` where commas separate declarators.
135	fn parse_one_declarator(ts: &mut TokenStream, base_ty: Type) -> Result<Stmt, CompileError> {
136	    // Handle pointer stars on each declarator: int *p, *q;
137	    let mut ty = base_ty;
138	    while ts.eat(TokenKind::Star) {
139	        ty = Type::Ptr(Box::new(ty));
140	    }
141	    // Function pointer: int (*fp)(int, int) or int (*table[4])(int)
142	    if ts.check(&TokenKind::LParen) && matches!(ts.lookahead(1), TokenKind::Star) {
143	        return parse_fn_ptr_declarator(ts, ty);
144	    }
145	    let name = ts.expect_ident()?;
146	    // Check for array: int a[N] or int a[N][M]
147	    let mut ty = ty;
148	    while ts.eat(TokenKind::LBracket) {
149	        let size = parse_const_array_size(ts)?;
150	        ts.expect(TokenKind::RBracket)?;
151	        ty = Type::Array(Box::new(ty), size);
152	    }
153	    // Struct/array brace initializer: struct s x = {1, 2};
154	    if ts.eat(TokenKind::Assign) {
155	        if ts.check(&TokenKind::LBrace) {
156	            return parse_brace_init(ts, name, ty);
157	        }
158	        let init = Some(parse_expr(ts)?);
159	        return Ok(Stmt::LocalDecl { name, ty, init });
160	    }
161	    Ok(Stmt::LocalDecl {
162	        name,
163	        ty,
164	        init: None,
165	    })
166	}
167	
168	/// Parse a function pointer declarator: (*name)(params) or (*name[N])(params)
169	/// Produces LocalDecl with Ptr(return_ty) or Array(Ptr(return_ty), N).
170	fn parse_fn_ptr_declarator(ts: &mut TokenStream, return_ty: Type) -> Result<Stmt, CompileError> {
171	    ts.expect(TokenKind::LParen)?; // (
172	    ts.expect(TokenKind::Star)?; // *
173	    let name = ts.expect_ident()?;
174	    // Optional array suffix: (*table[4])
175	    let mut is_array = None;
176	    if ts.eat(TokenKind::LBracket) {
177	        let size = parse_const_array_size(ts)?;
178	        ts.expect(TokenKind::RBracket)?;
179	        is_array = Some(size);
180	    }
181	    ts.expect(TokenKind::RParen)?; // )
182	    // Consume parameter list: (int, int, ...)
183	    ts.expect(TokenKind::LParen)?;
184	    skip_fn_ptr_params(ts)?;
185	    ts.expect(TokenKind::RParen)?;
186	    let ptr_ty = Type::Ptr(Box::new(return_ty));
187	    let ty = if let Some(size) = is_array {
188	        Type::Array(Box::new(ptr_ty), size)
189	    } else {
190	        ptr_ty
191	    };
192	    // Optional initializer
193	    let init = if ts.eat(TokenKind::Assign) {
194	        Some(parse_expr(ts)?)
195	    } else {
196	        None
197	    };
198	    Ok(Stmt::LocalDecl { name, ty, init })
199	}
200	
201	/// Skip a function pointer parameter list (balanced parens).
202	pub(crate) fn skip_fn_ptr_params(ts: &mut TokenStream) -> Result<(), CompileError> {
203	    if ts.check(&TokenKind::RParen) {
204	        return Ok(());
205	    }
206	    loop {
207	        while !ts.check(&TokenKind::RParen) && !ts.check(&TokenKind::Comma) {
208	            if ts.eat(TokenKind::LParen) {
209	                skip_fn_ptr_params(ts)?;
210	                ts.expect(TokenKind::RParen)?;
211	            } else {
212	                ts.advance();
213	            }
214	        }
215	        if !ts.eat(TokenKind::Comma) {
216	            break;
217	        }
218	    }
219	    Ok(())
220	}
221	
222	/// Parse brace initializer: struct s x = {1, 2};
223	/// Desugars to: LocalDecl x + member assignments.
224	fn parse_brace_init(ts: &mut TokenStream, name: String, ty: Type) -> Result<Stmt, CompileError> {
225	    ts.expect(TokenKind::LBrace)?;
226	    let mut values = Vec::new();
227	    if !ts.check(&TokenKind::RBrace) {
228	        loop {
229	            values.push(parse_expr(ts)?);
230	            if !ts.eat(TokenKind::Comma) {
231	                break;
232	            }
233	            // Allow trailing comma: {1, 2,}
234	            if ts.check(&TokenKind::RBrace) {
235	                break;
236	            }
237	        }
238	    }
239	    ts.expect(TokenKind::RBrace)?;
240	
241	    let mut stmts = vec![Stmt::LocalDecl {
242	        name: name.clone(),
243	        ty: ty.clone(),
244	        init: None,
245	    }];
246	
247	    // Generate member assignments based on struct member order
248	    if let Type::Struct { members, .. } = &ty {
249	        for (i, val) in values.into_iter().enumerate() {
250	            if let Some(member) = members.get(i) {
251	                stmts.push(Stmt::Expr(Expr::MemberAssign {
252	                    object: Box::new(Expr::Ident(name.clone())),
253	                    member: member.name.clone(),
254	                    value: Box::new(val),
255	                }));
256	            }
257	        }
258	    }
259	
260	    Ok(Stmt::Block(Block { stmts }))
261	}
