//! Expression entry point, assignment, unary, and primary parsing.

use tc24r_ast::{Expr, Type, UnaryOp};
use tc24r_error::CompileError;
use tc24r_parse_stream::TokenStream;
use tc24r_parser_compound::{desugar_compound, eat_compound_assign, make_assign};
use tc24r_parser_types::{is_type_start, parse_type};
use tc24r_token::TokenKind;

use crate::bitwise::parse_log_or;
use crate::stmt::parse_block;

/// Parse an expression.
pub fn parse_expr(ts: &mut TokenStream) -> Result<Expr, CompileError> {
    parse_assign(ts)
}

fn parse_assign(ts: &mut TokenStream) -> Result<Expr, CompileError> {
    let expr = parse_ternary(ts)?;
    if ts.eat(TokenKind::Assign) {
        let value = parse_assign(ts)?;
        return make_assign(expr, value);
    }
    if let Some(op) = eat_compound_assign(ts) {
        let rhs = parse_assign(ts)?;
        return desugar_compound(expr, op, rhs);
    }
    Ok(expr)
}

//! Expression AST nodes.

/// An expression node.
#[derive(Debug)]
pub enum Expr {
    IntLit(i32),
    StringLit(String),
    Ident(String),
    Assign {
        name: String,
        value: Box<Expr>,
    },
    Call {
        name: String,
        args: Vec<Expr>,
    },
    /// Indirect call through expression: expr(args)
    IndirectCall {
        callee: Box<Expr>,
        args: Vec<Expr>,
    },
    BinOp {
        op: BinOp,
        lhs: Box<Expr>,
        rhs: Box<Expr>,
    },
    UnaryOp {
        op: UnaryOp,
        operand: Box<Expr>,
    },
    /// Address-of: &x
    AddrOf(String),
    /// Pointer dereference: *p
    Deref(Box<Expr>),
    /// Cast expression: (type)expr
    Cast {
        ty: crate::Type,
        expr: Box<Expr>,
    },
    /// Dereference assignment: *p = val
    DerefAssign {
        ptr: Box<Expr>,
        value: Box<Expr>,
    },
    /// Pre-increment: ++i (returns new value)
    PreInc(String),
    /// Pre-decrement: --i (returns new value)
    PreDec(String),
    /// Post-increment: i++ (returns old value)
    PostInc(String),
    /// Post-decrement: i-- (returns old value)
    PostDec(String),
    /// Struct member access: expr.member
    MemberAccess {
        object: Box<Expr>,
        member: String,
    },
    /// Struct member assignment: expr.member = value
    MemberAssign {
        object: Box<Expr>,
        member: String,
        value: Box<Expr>,
    },
    /// GCC statement expression: ({ stmt1; stmt2; expr; })
    StmtExpr(crate::Block),
    /// Ternary: cond ? then_expr : else_expr
    Ternary {
        cond: Box<Expr>,
        then_expr: Box<Expr>,
        else_expr: Box<Expr>,
    },
}

/// Binary operator.
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum BinOp {
    Add,
    Sub,
    Mul,
    Div,
    Mod,
    BitAnd,
    BitOr,
    BitXor,
    Shl,
    Shr,
    Eq,
    Ne,
    Lt,
    Gt,
    Le,
    Ge,
    LogAnd,
    LogOr,
}

/// Unary operator.
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum UnaryOp {
    Neg,
    BitNot,
    LogNot,
}

